const email = $input.first().json;

let body = (email.textPlain || email.snippet || email.text || '').trim();
const markers = [/\n--\s*\n/, /\nOn .+ wrote:\n/i, /\nDen .+ skrev:\n/i];
for (const m of markers) {
  const idx = body.search(m);
  if (idx > 0) body = body.substring(0, idx).trim();
}

const from = email.from || '';
const fromMatch = from.match(/^(.+?)\s*<(.+?)>$/);
const senderName = fromMatch ? fromMatch[1].trim() : '';
const senderEmail = fromMatch ? fromMatch[2].trim() : from.trim();

return [{
  json: {
    senderName,
    senderEmail,
    subject: email.subject || '',
    body,
    threadId: email.threadId || email.id,
    messageId: email.id || email.messageId
  }
}];

const email = $('Extract Email').first().json;
const kbRaw = $('Fetch Knowledge Base').first().json;
const kb = kbRaw.data || (typeof kbRaw === 'string' ? kbRaw : '');

const userMessage = 'Skriv ett utkast till svar p\u00e5 detta mejl.\n'
  + 'F\u00f6lj instruktionerna i din knowledge base exakt.\n'
  + 'Svara BARA med mejltexten - inget annat. Ingen f\u00f6rklaring, bara sj\u00e4lva mejlet.\n\n'
  + 'Fr\u00e5n: ' + (email.senderName || 'Ok\u00e4nd') + ' <' + email.senderEmail + '>\n'
  + '\u00c4mne: ' + email.subject + '\n\n'
  + email.body;

const requestBody = JSON.stringify({
  model: 'claude-sonnet-4-5-20250929',
  max_tokens: 1024,
  temperature: 0.3,
  system: kb,
  messages: [{ role: 'user', content: userMessage }]
});

return [{
  json: {
    requestBody,
    senderEmail: email.senderEmail,
    subject: email.subject,
    threadId: email.threadId
  }
}];

const response = $input.first().json;
const draft = response.content[0].text;
const draftHtml = draft.replace(/\n/g, '<br>');

return [{
  json: { draftHtml }
}];
